insert into content_tips (id, course_id, unit_order, cefr_level, skill, type, topic, title, body, example) values
('774fc041-8c84-5eed-8b9e-18d2f6ec8a45'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,1,'A1',$p$speaking$p$,$p$gramatica$p$,$p$tu_vous_etre$p$,$p$«tu» para amigos, «vous» para respeto$p$,$p$El francés distingue el trato como el español (tú/usted): «tu es» es informal (con amigos y familia) y «vous êtes» es formal (con desconocidos o mayores). Fíjate en el verbo être: cambia de «es» a «êtes» según a quién hablas. Al preguntar el nombre también cambia todo: «Comment tu t'appelles ?» vs «Comment vous appelez-vous ?».$p$,$p$Tu es espagnol. · Vous êtes espagnol. · Comment tu t'appelles ? · Comment vous appelez-vous ?$p$),
('6369a27a-3b98-5191-bef7-b4d4a45b1a92'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,2,'A1',$p$grammar$p$,$p$error_comun$p$,$p$edad_avoir$p$,$p$En francés NO «eres» 20 años: los «tienes»$p$,$p$La edad se dice con el verbo avoir (tener), no con être (ser). Nunca digas «Je suis 20 ans» (calco del inglés/español): es «J'ai vingt ans», literalmente «tengo veinte años». Y no olvides la palabra «ans» al final: sin ella la frase queda incompleta.$p$,$p$J'ai vingt ans. · Tu as quel âge ? · Elle a trente ans.$p$),
('44debb2b-d95f-50e8-941f-a749f7365e08'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,3,'A1',$p$grammar$p$,$p$gramatica$p$,$p$posesivos$p$,$p$«mon» o «ma»: manda el género de LA COSA$p$,$p$El posesivo concuerda con el objeto poseído, no con quien posee: mon (masculino), ma (femenino) y mes (plural, ambos géneros). Por eso es «mon frère» (hermano, masc.) pero «ma sœur» (hermana, fem.), aunque el dueño sea la misma persona. Truco: ante palabra femenina que empieza por vocal se usa «mon» por sonido (mon amie).$p$,$p$mon frère · ma sœur · mes parents · mon amie$p$),
('18aef8be-0276-5382-a89f-0d4b319987fb'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,4,'A1',$p$grammar$p$,$p$gramatica$p$,$p$partitivo$p$,$p$«du pain»: un poco de, no todo el pan$p$,$p$Ante comida y cantidades no contables, el francés usa el partitivo (una cantidad indeterminada) donde el español no pone nada: du (masc.), de la (fem.), de l' (ante vocal o h muda) y des (plural). «Je mange du pain» = «como (algo de) pan». No lo omitas: «Je mange pain» es incorrecto.$p$,$p$du pain · de la viande · de l'eau · des pommes$p$),
('c13dc880-8280-571f-8480-5842227c0f45'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,5,'A1',$p$grammar$p$,$p$error_comun$p$,$p$la_hora$p$,$p$«et demie», pero con mediodía «et demi»$p$,$p$La hora se dice con «Il est…»: «Il est trois heures» (son las tres), y para los minutos «et quart» (y cuarto) y «et demie» (y media). Ojo con la trampa: «demie» lleva -e porque concuerda con «heure» (femenino), PERO con midi y minuit (masculinos) se escribe «demi» sin -e: «midi et demi».$p$,$p$Il est trois heures et quart. · Il est cinq heures et demie. · Il est midi et demi.$p$),
('14c1ea67-3ec7-584b-9ccf-91d2b96877b6'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,6,'A1',$p$grammar$p$,$p$gramatica$p$,$p$contracciones$p$,$p$à + le = au, de + le = du (obligatorio)$p$,$p$En francés à y de se fusionan con el artículo «le»: à + le = au, de + le = du. No es opcional, es obligatorio: se dice «au restaurant», nunca «à le restaurant». Con «la» y «l'» no hay fusión (à la gare, de l'école); solo se contraen «le» y «les» (à les = aux, de les = des).$p$,$p$au restaurant · en face du musée · à la gare · aux États-Unis$p$),
('364d7a1b-a3c9-5175-a387-13613ea03a44'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,1,'A1',$p$grammar$p$,$p$gramatica$p$,$p$tu_lei_essere$p$,$p$Al usted italiano lo tratas de «ella»$p$,$p$Con «tu» (informal) el verbo va en 2ª persona: «tu sei». Pero el «usted» italiano es «Lei» y SIEMPRE lleva el verbo en 3ª persona del singular, como si hablaras de «ella»: «Lei è». Por eso «¿Cómo te llamas?» es «Come ti chiami?» y su versión formal es «Come si chiama?».$p$,$p$tu sei · Lei è · Come ti chiami? · Come si chiama?$p$),
('cd1e020f-ce22-5b50-9955-a048a5dc96f1'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,2,'A1',$p$grammar$p$,$p$error_comun$p$,$p$edad_avere$p$,$p$En italiano la edad se TIENE, no se es$p$,$p$El error clásico del hispanohablante es calcar «Sono 20 anni» del inglés/español. En italiano la edad se dice con AVERE (tener), igual que en español: «tengo 20 años» → «Ho vent'anni». Fíjate en la elisión: venti + anni se apostrofa en «vent'anni».$p$,$p$Ho vent'anni · Quanti anni hai? · Ho trent'anni$p$),
('adc540c0-b830-521c-b826-474b7e5e1862'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,3,'A1',$p$grammar$p$,$p$gramatica$p$,$p$posesivos$p$,$p$Con un familiar, quita el artículo$p$,$p$En italiano los posesivos normalmente llevan artículo, PERO con parientes en singular se omite: «mio fratello», «mia madre» (no «il mio fratello»). En cuanto pasas al plural, el artículo vuelve: «i miei genitori», «le mie sorelle».$p$,$p$mio fratello · mia madre · i miei genitori · le mie sorelle$p$),
('ca807c86-fc58-591a-a64f-754d613a0365'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,4,'A1',$p$grammar$p$,$p$gramatica$p$,$p$partitivo$p$,$p$«Un poco de» se fusiona en una palabra$p$,$p$El partitivo expresa una cantidad indefinida («algo de pan, un poco de agua») y nace de fundir «di» con el artículo: di+il=del, di+la=della, y ante vocal se elide en dell'. En plural son dei / degli / delle.$p$,$p$del pane · della carne · dell'acqua · delle mele$p$),
('878ae63b-27ec-5aaf-89dc-b02a8278b252'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,5,'A1',$p$grammar$p$,$p$gramatica$p$,$p$la_hora$p$,$p$La una es singular, las demás plural$p$,$p$Solo la una lleva verbo y artículo en singular: «È l'una». Todas las otras horas van en plural: «Sono le tre», «Sono le dieci». Los minutos se añaden con «e»: «e mezza» (y media), «e un quarto» (y cuarto).$p$,$p$È l'una · Sono le tre · Sono le otto e mezza · Sono le due e un quarto$p$),
('718ac1f9-9089-51c9-bca5-ec48467996e6'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,6,'A1',$p$grammar$p$,$p$gramatica$p$,$p$prep_articuladas$p$,$p$Preposición + artículo = una sola palabra$p$,$p$En italiano la preposición se pega al artículo y forma una palabra única: a+il=al, a+la=alla, da+la=dalla, di+il=del. No es opcional como en español: se dice «vado al ristorante», no «a il ristorante».$p$,$p$al ristorante · vicino alla stazione · vengo dalla Spagna · la porta del bagno$p$),
('6b620cca-e17d-5671-9010-0e8339f24d81'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,1,'A1',$p$writing$p$,$p$gramatica$p$,$p$verbo_sein$p$,$p$«sein» es el verbo que lo abre todo$p$,$p$Igual que «ser/estar», «sein» es irregular y no se parece a su infinitivo: memorízalo como una cancioncita. Con «Sie» formal (usted) usas la misma forma que el plural «sie/wir»: «sind».$p$,$p$ich bin · du bist · er/sie/es ist · wir sind · ihr seid · sie/Sie sind$p$),
('0df6d5eb-21f2-57d0-8ef8-d812a50aa229'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,2,'A1',$p$speaking$p$,$p$error_comun$p$,$p$edad$p$,$p$Tu edad la dice «sein», no «haben»$p$,$p$En español «tienes» años, pero en alemán los años los ERES, no los tienes. Di «Ich bin … Jahre alt» y evita el clásico calco «Ich habe … Jahre», que suena a error de principiante.$p$,$p$Ich bin zwanzig Jahre alt. · Wie alt bist du? — Ich bin dreißig. (nunca «Ich habe 20 Jahre»)$p$),
('16843c54-b4df-5cfb-a3e2-e8fac7f30f76'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,3,'A1',$p$reading$p$,$p$gramatica$p$,$p$possessiv_mein_meine$p$,$p$«mein» o «meine»: manda el sustantivo$p$,$p$El posesivo cambia según el GÉNERO de lo poseído, no de quien posee. «mein» acompaña a masculinos y neutros; «meine» a femeninos y a TODO el plural. Fíjate siempre en el sustantivo que sigue.$p$,$p$mein Bruder · mein Kind · meine Schwester · meine Eltern$p$),
('b4bcb190-77d4-5c62-a89d-7c830bd191c5'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,4,'A1',$p$writing$p$,$p$gramatica$p$,$p$akkusativ_unbestimmt$p$,$p$En acusativo solo el masculino se disfraza$p$,$p$Cuando algo es el objeto directo (lo que quieres, pides o ves), el artículo indefinido masculino «ein» se convierte en «einen». El femenino «eine» y el neutro «ein» no se mueven ni un pelo.$p$,$p$Ich möchte einen Kaffee. · Ich möchte eine Milch. · Ich möchte ein Wasser.$p$),
('46036d5a-37f3-5e5b-85f2-af5ceea430b5'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,5,'A1',$p$listening$p$,$p$error_comun$p$,$p$viertel_halb$p$,$p$«halb vier» son las 3:30, no las 4:30$p$,$p$¡Ojo, falso amigo! Los alemanes cuentan la media hora mirando HACIA ADELANTE: «halb vier» significa media hora antes de las cuatro, o sea 3:30. «Viertel nach» es «y cuarto» y «Viertel vor» es «menos cuarto».$p$,$p$Es ist drei Uhr. · Viertel nach drei (3:15) · halb vier (3:30) · Viertel vor vier (3:45)$p$),
('068ae775-cc27-5d32-aec6-d6b45c96e413'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,6,'A1',$p$speaking$p$,$p$gramatica$p$,$p$wo_ist$p$,$p$«Wo ist…?» pregunta, «Es gibt…» sitúa$p$,$p$Para ubicar algo pregunta «Wo ist…?» (¿Dónde está…?) y para decir que algo existe usa «Es gibt…» (hay), que pide acusativo. Guarda tres flechas para las direcciones: links, rechts, geradeaus.$p$,$p$Wo ist der Bahnhof? · Es gibt einen Supermarkt hier. · links · rechts · geradeaus$p$),
('9b40c029-40fa-5436-8faa-e97c47c18c47'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,1,'A1',$p$speaking$p$,$p$gramatica$p$,$p$verbo_zijn$p$,$p$Zijn: el verbo que no sigue reglas$p$,$p$El verbo «zijn» (ser/estar) es irregular y lo usarás en cada frase, así que memorízalo entero de una vez. Fíjate en que «u bent» (usted) lleva la misma forma que «jij bent», aunque «u» es formal.$p$,$p$ik ben · jij bent · hij is · u bent$p$),
('87bc076f-a39b-53bb-890b-6140d2381c8f'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,2,'A1',$p$writing$p$,$p$error_comun$p$,$p$leeftijd$p$,$p$Tu edad va con «zijn», no con «hebben»$p$,$p$En español «tienes» 20 años, pero en neerlandés se dice literalmente que «eres» 20 años: se usa «zijn», no «hebben». Decir «Ik heb 20 jaar» es un error muy típico del hispanohablante que un neerlandés notará enseguida.$p$,$p$Ik ben twintig jaar oud.$p$),
('5e2523ca-e6a9-508b-9577-55e1bf588e5d'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,3,'A1',$p$reading$p$,$p$mnemotecnia$p$,$p$articulo_het$p$,$p$De o het: memoriza los het$p$,$p$Casi todas las palabras llevan «de», así que no intentes aprenderte esas: aprende de memoria las que llevan «het», que son menos y no siguen una regla infalible. Cada vez que veas una palabra nueva con «het», guárdala junto con su artículo.$p$,$p$het water · het brood · het kind · het station · het museum$p$),
('a65c3cc7-2850-54a6-9522-55b334b73aea'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,4,'A1',$p$speaking$p$,$p$cultura$p$,$p$pedir$p$,$p$Pedir con «graag» suena amable$p$,$p$En el café, «Ik wil graag…» equivale a «me gustaría…» y suena mucho más cortés que un «ik wil» a secas. Añade «alstublieft» (por favor, formal) al final y pregunta el precio con «Wat kost het?» o «Hoeveel kost het?».$p$,$p$Ik wil graag een koffie, alstublieft. Wat kost het?$p$),
('248058c6-6f98-50d2-97ba-00123028cc95'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,5,'A1',$p$listening$p$,$p$error_comun$p$,$p$kwart$p$,$p$«Half vier» son las 3:30, no las 4:30$p$,$p$Cuidado con este falso amigo: «half vier» no es «cuatro y media», sino la media hora ANTES de las cuatro, es decir, las 3:30. El neerlandés mira hacia la hora que viene, no hacia la que pasó. Para los cuartos usa «kwart over» (y cuarto) y «kwart voor» (menos cuarto).$p$,$p$Het is half vier. · kwart over drie · kwart voor vier$p$),
('e4c60bbd-33b0-5f83-9d52-1215c5589dbe'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,6,'A1',$p$reading$p$,$p$gramatica$p$,$p$waar$p$,$p$«Er is» y «er zijn» para ubicar$p$,$p$Para preguntar dónde está algo usa «Waar is…?», y para decir que algo existe o hay algo usa «er is» (singular) o «er zijn» (plural), parecido al «hay» del español. Combínalo con las direcciones básicas para orientarte.$p$,$p$Waar is het station? Er is een café links, en er zijn winkels rechtdoor.$p$)
